const fs = require('fs');

fs.readFile('data.txt', 'utf8', (err, data) => {
  if (err) {
    console.error('Erreur de lecture :', err.message);
    return;
  }
  const newContent = data + ' - Date : ' + Date.now();
  fs.writeFile('data.txt', newContent, 'utf8', (err) => {
    if (err) {
      console.error('Erreur d\'écriture :', err.message);
      return;
    }
    console.log('Fichier mis à jour avec succès');
    fs.readFile('data.txt', 'utf8', (err, finalData) => {
      if (err) {
        console.error('Erreur de relecture :', err.message);
        return;
      }
      console.log('Contenu final :', finalData);
    });
  });
});
