const fs = require('fs').promises;
const path = require('path');

async function nettoyerTemp() {
  const dossier = './temp';
  try {
    const fichiers = await fs.readdir(dossier);
    for (const fichier of fichiers) {
      const cheminComplet = path.join(dossier, fichier);
      const stats = await fs.stat(cheminComplet);
      if (stats.isFile() && path.extname(fichier) === '.tmp') {
        await fs.unlink(cheminComplet);
        console.log(`Supprimé : ${fichier}`);
      }
    }
    console.log('Nettoyage terminé');
  } catch (err) {
    console.error('Erreur :', err.message);
  }
}

nettoyerTemp();
```

