```javascript
const fs = require('fs').promises;
const path = require('path');

async function sauvegarder() {
  const dossierSource = './data';
  const dossierBackup = './backup';
  const today = new Date().toISOString().slice(0,10); // AAAA-MM-JJ

  try {
    // Création du dossier backup si besoin
    await fs.mkdir(dossierBackup, { recursive: true });

    // Lecture du dossier source
    const fichiers = await fs.readdir(dossierSource);

    for (const fichier of fichiers) {
      const cheminSource = path.join(dossierSource, fichier);
      const stats = await fs.stat(cheminSource);

      if (stats.isFile()) {
        const ext = path.extname(fichier);
        let nomDestination;

        if (ext === '.txt') {
          nomDestination = `${path.basename(fichier, ext)}_${today}.txt`;
          const contenu = await fs.readFile(cheminSource, 'utf8');
          await fs.writeFile(path.join(dossierBackup, nomDestination), contenu, 'utf8');
        } else {
          nomDestination = fichier;
          await fs.copyFile(cheminSource, path.join(dossierBackup, nomDestination));
        }
        console.log(`Sauvegardé : ${fichier} -> ${nomDestination}`);
      }
    }
    console.log('Backup terminé avec succès');
  } catch (err) {
    console.error('Échec de la sauvegarde :', err.message);
  }
}

sauvegarder();
```
